# Minimal valid 1x1 red PNG (67 bytes)
TINY_PNG_B64 = (
    "iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4"
    "2mP8/58BAwAI/AL+hc2rNAAAAABJRU5ErkJggg=="
)
TINY_PNG_BYTES = base64.b64decode(TINY_PNG_B64)

# Fake Claude stream-json output lines
CLAUDE_STREAM_LINES = [
    json.dumps({"type": "assistant", "message": {"content": [{"type": "text", "text": "Hello from mock"}]}}).encode() + b"\n",
    json.dumps({"type": "result", "result": "Hello from mock", "total_cost_usd": 0.01, "usage": {"input_tokens": 10, "output_tokens": 5}}).encode() + b"\n",
]


def _make_mock_process(stdout_lines: list[bytes], exit_code: int = 0):
    """Build a mock asyncio.subprocess.Process with canned stdout."""
    proc = AsyncMock()
    proc.returncode = exit_code
    proc.kill = MagicMock()

    line_iter = iter(stdout_lines + [b""])  # empty bytes = EOF

    async def readline():
        return next(line_iter, b"")

    proc.stdout = AsyncMock()
    proc.stdout.readline = readline

    # stderr — return empty
    async def read_stderr():
        return b""

    proc.stderr = AsyncMock()
    proc.stderr.read = read_stderr

    async def wait():
        pass

    proc.wait = wait
    return proc


