class TestChatEndpoint:
    @pytest.mark.asyncio
    async def test_basic_chat(self, app_client):
        """POST /chat returns structured JSON with response text."""
        mock_proc = _make_mock_process(CLAUDE_STREAM_LINES, exit_code=0)

        with patch("server.asyncio.create_subprocess_exec", return_value=mock_proc):
            async with AsyncClient(transport=ASGITransport(app=app_client), base_url="http://test") as ac:
                resp = await ac.post("/chat", json={"prompt": "Say hello", "model": "sonnet"})

        assert resp.status_code == 200
        body = resp.json()
        assert body["response"] == "Hello from mock"
        assert body["backend"] == "claude"
        assert body["exit_code"] == 0
        assert body["duration_ms"] >= 0
        assert body["cost_usd"] == 0.01
        assert body["tokens_in"] == 10
        assert body["tokens_out"] == 5

