    async def test_chat_with_input_images(self, app_client):
        """POST /chat with images writes temp files and passes to _build_cmd."""
        mock_proc = _make_mock_process(CLAUDE_STREAM_LINES, exit_code=0)

        with patch("server.asyncio.create_subprocess_exec", return_value=mock_proc) as mock_exec:
            async with AsyncClient(transport=ASGITransport(app=app_client), base_url="http://test") as ac:
                resp = await ac.post("/chat", json={
                    "prompt": "Review this screenshot",
                    "model": "sonnet",
                    "images": [{"data": TINY_PNG_B64, "media_type": "image/png", "filename": "shot.png"}],
                })

        assert resp.status_code == 200
        # Verify the command included the image reference in the prompt
        call_args = mock_exec.call_args
        cmd = call_args[0]  # positional args to create_subprocess_exec
        prompt_arg = cmd[2]  # after cli and -p
        assert "[Image:" in prompt_arg
        assert "shot.png" in prompt_arg

