    def test_build_cmd_disables_gemini_sandbox(self, app_client):
        """Gemini CLI must explicitly disable sandbox inside the Docker subagent."""
        import server

        server.BACKENDS = {
            "gemini": {
                "cli": "gemini",
                "prompt_flag": "-p",
                "output_flags": ["--sandbox", "false", "--yolo"],
                "max_turns_flag": None,
                "model_flag": "--model",
                "system_prompt_flag": None,
                "image_flag": "-f",
            }
        }

        cmd = server._build_cmd("gemini", "gemini-2.5-flash", "say hi")
        assert "--sandbox" in cmd
        assert "false" in cmd
        assert "--yolo" in cmd


