class TestChatStreamEndpoint:
    @pytest.mark.asyncio
    async def test_basic_stream(self, app_client):
        """POST /chat/stream returns SSE events including meta, text/result, and done."""
        mock_proc = _make_mock_process(CLAUDE_STREAM_LINES, exit_code=0)

        with patch("server.asyncio.create_subprocess_exec", return_value=mock_proc):
            async with AsyncClient(transport=ASGITransport(app=app_client), base_url="http://test") as ac:
                resp = await ac.post("/chat/stream", json={"prompt": "Hello", "model": "sonnet"})

        assert resp.status_code == 200
        assert "text/event-stream" in resp.headers["content-type"]

        # Parse SSE events from body
        events = _parse_sse(resp.text)
        event_types = [e["event"] for e in events]

        assert "meta" in event_types
        assert "done" in event_types

        # Meta event has backend info
        meta = next(e for e in events if e["event"] == "meta")
        assert meta["data"]["backend"] == "claude"

        # Done event has exit_code
        done = next(e for e in events if e["event"] == "done")
        assert done["data"]["exit_code"] == 0

    @pytest.mark.asyncio
    async def test_stream_with_output_images(self, app_client, tmp_path):
        """POST /chat/stream emits an images event when output images exist."""
        mock_proc = _make_mock_process(CLAUDE_STREAM_LINES, exit_code=0)
        out_dir = tmp_path / "stream_output"
        out_dir.mkdir()
        (out_dir / "generated.png").write_bytes(TINY_PNG_BYTES)

        with patch("server.asyncio.create_subprocess_exec", return_value=mock_proc):
            async with AsyncClient(transport=ASGITransport(app=app_client), base_url="http://test") as ac:
                resp = await ac.post("/chat/stream", json={
                    "prompt": "Make an image",
                    "model": "sonnet",
                    "output_dir": str(out_dir),
                })

        events = _parse_sse(resp.text)
        event_types = [e["event"] for e in events]

        # images event must come before done
        assert "images" in event_types
        assert "done" in event_types
        img_idx = event_types.index("images")
        done_idx = event_types.index("done")
        assert img_idx < done_idx

        img_event = events[img_idx]
        assert img_event["data"]["count"] == 1
        assert img_event["data"]["images"][0]["filename"] == "generated.png"

    @pytest.mark.asyncio
    async def test_stream_no_images_when_empty(self, app_client, tmp_path):
        """POST /chat/stream does NOT emit images event when output dir is empty."""
        mock_proc = _make_mock_process(CLAUDE_STREAM_LINES, exit_code=0)
